import{i as e,r as t,s as n,t as r}from"./app-B1jqjtqq.js";var i=JSON.parse(`{"path":"/java-tutor/orm-tutor/mysql/06-functions.html","title":"MySQL 常用函数","lang":"zh-CN","frontmatter":{"description":"MySQL 常用函数 MySQL 内置函数大全，按功能分类。 字符串函数 数字函数 日期函数 聚合函数 条件函数 JSON 函数（MySQL 5.7+） 加密函数 信息函数 练习","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"MySQL 常用函数\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-13T07:23:11.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/java-tutor/orm-tutor/mysql/06-functions.html"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"MySQL 常用函数"}],["meta",{"property":"og:description","content":"MySQL 常用函数 MySQL 内置函数大全，按功能分类。 字符串函数 数字函数 日期函数 聚合函数 条件函数 JSON 函数（MySQL 5.7+） 加密函数 信息函数 练习"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-13T07:23:11.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-13T07:23:11.000Z"}]]},"git":{"createdTime":1783927391000,"updatedTime":1783927391000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":1,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":3.81,"words":1143},"filePathRelative":"java-tutor/orm-tutor/mysql/06-functions.md","autoDesc":true}`),a={name:`06-functions.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="mysql-常用函数" tabindex="-1"><a class="header-anchor" href="#mysql-常用函数"><span>MySQL 常用函数</span></a></h1><blockquote><p>MySQL 内置函数大全，按功能分类。</p></blockquote><h2 id="字符串函数" tabindex="-1"><a class="header-anchor" href="#字符串函数"><span>字符串函数</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- CONCAT — 字符串拼接</span></span>
<span class="line"><span class="token keyword">SELECT</span> CONCAT<span class="token punctuation">(</span><span class="token string">&#39;Hello&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39; &#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;World&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- Hello World</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- CONCAT_WS — 带分隔符拼接</span></span>
<span class="line"><span class="token keyword">SELECT</span> CONCAT_WS<span class="token punctuation">(</span><span class="token string">&#39;-&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;2024&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;01&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;15&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 2024-01-15</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- LENGTH — 字节长度</span></span>
<span class="line"><span class="token keyword">SELECT</span> LENGTH<span class="token punctuation">(</span><span class="token string">&#39;Hello&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 5</span></span>
<span class="line"><span class="token keyword">SELECT</span> LENGTH<span class="token punctuation">(</span><span class="token string">&#39;你好&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>    <span class="token comment">-- 6（UTF-8 下中文占 3 字节）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- CHAR_LENGTH — 字符长度</span></span>
<span class="line"><span class="token keyword">SELECT</span> CHAR_LENGTH<span class="token punctuation">(</span><span class="token string">&#39;你好&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 2</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- SUBSTRING — 截取</span></span>
<span class="line"><span class="token keyword">SELECT</span> SUBSTRING<span class="token punctuation">(</span><span class="token string">&#39;Hello World&#39;</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- Hello（索引从 1 开始）</span></span>
<span class="line"><span class="token keyword">SELECT</span> SUBSTRING<span class="token punctuation">(</span><span class="token string">&#39;Hello World&#39;</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">-- World</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- REPLACE — 替换</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">REPLACE</span><span class="token punctuation">(</span><span class="token string">&#39;Hello World&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;World&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;MySQL&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- Hello MySQL</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- UPPER / LOWER — 大小写转换</span></span>
<span class="line"><span class="token keyword">SELECT</span> UPPER<span class="token punctuation">(</span><span class="token string">&#39;hello&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- HELLO</span></span>
<span class="line"><span class="token keyword">SELECT</span> LOWER<span class="token punctuation">(</span><span class="token string">&#39;HELLO&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- hello</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- TRIM — 去除空格</span></span>
<span class="line"><span class="token keyword">SELECT</span> TRIM<span class="token punctuation">(</span><span class="token string">&#39;  Hello  &#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>    <span class="token comment">-- Hello</span></span>
<span class="line"><span class="token keyword">SELECT</span> LTRIM<span class="token punctuation">(</span><span class="token string">&#39;  Hello&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">-- Hello</span></span>
<span class="line"><span class="token keyword">SELECT</span> RTRIM<span class="token punctuation">(</span><span class="token string">&#39;Hello  &#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">-- Hello</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- LPAD / RPAD — 填充</span></span>
<span class="line"><span class="token keyword">SELECT</span> LPAD<span class="token punctuation">(</span><span class="token string">&#39;5&#39;</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;0&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 005</span></span>
<span class="line"><span class="token keyword">SELECT</span> RPAD<span class="token punctuation">(</span><span class="token string">&#39;5&#39;</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;0&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 500</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- LOCATE — 查找位置</span></span>
<span class="line"><span class="token keyword">SELECT</span> LOCATE<span class="token punctuation">(</span><span class="token string">&#39;World&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;Hello World&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 7</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- REVERSE — 反转</span></span>
<span class="line"><span class="token keyword">SELECT</span> REVERSE<span class="token punctuation">(</span><span class="token string">&#39;Hello&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- olleH</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- REPEAT — 重复</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">REPEAT</span><span class="token punctuation">(</span><span class="token string">&#39;Ha&#39;</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- HaHaHa</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- LEFT / RIGHT — 取左右字符</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">LEFT</span><span class="token punctuation">(</span><span class="token string">&#39;Hello&#39;</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- He</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">RIGHT</span><span class="token punctuation">(</span><span class="token string">&#39;Hello&#39;</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- lo</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- FORMAT — 数字格式化</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">FORMAT</span><span class="token punctuation">(</span><span class="token number">1234567.89</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 1,234,567.89</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="数字函数" tabindex="-1"><a class="header-anchor" href="#数字函数"><span>数字函数</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- ABS — 绝对值</span></span>
<span class="line"><span class="token keyword">SELECT</span> ABS<span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 10</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- CEIL / FLOOR — 向上/向下取整</span></span>
<span class="line"><span class="token keyword">SELECT</span> CEIL<span class="token punctuation">(</span><span class="token number">3.14</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 4</span></span>
<span class="line"><span class="token keyword">SELECT</span> FLOOR<span class="token punctuation">(</span><span class="token number">3.14</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 3</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- ROUND — 四舍五入</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">ROUND</span><span class="token punctuation">(</span><span class="token number">3.14159</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 3.14</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- TRUNCATE — 截断</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">TRUNCATE</span><span class="token punctuation">(</span><span class="token number">3.14159</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 3.14</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- POW / SQRT — 幂/平方根</span></span>
<span class="line"><span class="token keyword">SELECT</span> POW<span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 1024</span></span>
<span class="line"><span class="token keyword">SELECT</span> SQRT<span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>    <span class="token comment">-- 10</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- RAND — 随机数（0-1）</span></span>
<span class="line"><span class="token keyword">SELECT</span> RAND<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> FLOOR<span class="token punctuation">(</span>RAND<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token number">100</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">;</span>  <span class="token comment">-- 1-100 随机整数</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- MOD — 取模</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">MOD</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 1</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- SIGN — 符号（负数=-1, 0=0, 正数=1）</span></span>
<span class="line"><span class="token keyword">SELECT</span> SIGN<span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- -1</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- GREATEST / LEAST — 最大/最小值</span></span>
<span class="line"><span class="token keyword">SELECT</span> GREATEST<span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 20</span></span>
<span class="line"><span class="token keyword">SELECT</span> LEAST<span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>      <span class="token comment">-- 5</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="日期函数" tabindex="-1"><a class="header-anchor" href="#日期函数"><span>日期函数</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- NOW — 当前日期时间</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>              <span class="token comment">-- 2024-01-15 14:30:25</span></span>
<span class="line"><span class="token keyword">SELECT</span> CURDATE<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>          <span class="token comment">-- 2024-01-15</span></span>
<span class="line"><span class="token keyword">SELECT</span> CURTIME<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>          <span class="token comment">-- 14:30:25</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- DATE / TIME / YEAR / MONTH / DAY</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">DATE</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>        <span class="token comment">-- 2024-01-15</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">TIME</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>        <span class="token comment">-- 14:30:25</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">YEAR</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>        <span class="token comment">-- 2024</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">MONTH</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>       <span class="token comment">-- 1</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">DAY</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>         <span class="token comment">-- 15</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">HOUR</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>        <span class="token comment">-- 14</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">MINUTE</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>      <span class="token comment">-- 30</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">SECOND</span><span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>      <span class="token comment">-- 25</span></span>
<span class="line"><span class="token keyword">SELECT</span> DAYOFWEEK<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 2（周日=1, 周一=2, ...）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 日期格式化</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATE_FORMAT<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&#39;%Y-%m-%d %H:%i:%s&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 2024-01-15 14:30:25</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATE_FORMAT<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&#39;%Y年%m月%d日&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>         <span class="token comment">-- 2024年01月15日</span></span>
<span class="line"><span class="token comment">-- 常用格式符: %Y(年), %m(月), %d(日), %H(24时), %h(12时), %i(分), %s(秒), %W(星期)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 日期加减</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATE_ADD<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token keyword">INTERVAL</span> <span class="token number">1</span> <span class="token keyword">DAY</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">-- 明天</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATE_ADD<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token keyword">INTERVAL</span> <span class="token number">1</span> <span class="token keyword">MONTH</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 下月</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATE_SUB<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token keyword">INTERVAL</span> <span class="token number">1</span> <span class="token keyword">YEAR</span><span class="token punctuation">)</span><span class="token punctuation">;</span>    <span class="token comment">-- 去年</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 日期差</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATEDIFF<span class="token punctuation">(</span><span class="token string">&#39;2024-12-31&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;2024-01-01&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 365</span></span>
<span class="line"><span class="token keyword">SELECT</span> TIMESTAMPDIFF<span class="token punctuation">(</span><span class="token keyword">MONTH</span><span class="token punctuation">,</span> <span class="token string">&#39;2024-01-01&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;2024-12-31&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 11</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 提取</span></span>
<span class="line"><span class="token keyword">SELECT</span> EXTRACT<span class="token punctuation">(</span><span class="token keyword">YEAR</span> <span class="token keyword">FROM</span> <span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>    <span class="token comment">-- 2024</span></span>
<span class="line"><span class="token keyword">SELECT</span> EXTRACT<span class="token punctuation">(</span><span class="token keyword">MONTH</span> <span class="token keyword">FROM</span> <span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">-- 1</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- LAST_DAY — 当月最后一天</span></span>
<span class="line"><span class="token keyword">SELECT</span> LAST_DAY<span class="token punctuation">(</span><span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 2024-01-31</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 字符串 → 日期</span></span>
<span class="line"><span class="token keyword">SELECT</span> STR_TO_DATE<span class="token punctuation">(</span><span class="token string">&#39;2024-01-15&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;%Y-%m-%d&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 2024-01-15</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="聚合函数" tabindex="-1"><a class="header-anchor" href="#聚合函数"><span>聚合函数</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- COUNT — 计数</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">FROM</span> students<span class="token punctuation">;</span>               <span class="token comment">-- 总行数</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span>score<span class="token punctuation">)</span> <span class="token keyword">FROM</span> students<span class="token punctuation">;</span>           <span class="token comment">-- 非 NULL 的行数</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token keyword">DISTINCT</span> class_id<span class="token punctuation">)</span> <span class="token keyword">FROM</span> students<span class="token punctuation">;</span>  <span class="token comment">-- 去重计数</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- SUM — 求和</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">SUM</span><span class="token punctuation">(</span>score<span class="token punctuation">)</span> <span class="token keyword">FROM</span> students<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- AVG — 平均值</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">AVG</span><span class="token punctuation">(</span>score<span class="token punctuation">)</span> <span class="token keyword">FROM</span> students<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- MAX / MIN — 最大/最小值</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token function">MAX</span><span class="token punctuation">(</span>score<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token function">MIN</span><span class="token punctuation">(</span>score<span class="token punctuation">)</span> <span class="token keyword">FROM</span> students<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- GROUP_CONCAT — 分组拼接</span></span>
<span class="line"><span class="token keyword">SELECT</span> class_id<span class="token punctuation">,</span> GROUP_CONCAT<span class="token punctuation">(</span>name <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> id SEPARATOR <span class="token string">&#39;, &#39;</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> names</span>
<span class="line"><span class="token keyword">FROM</span> students <span class="token keyword">GROUP</span> <span class="token keyword">BY</span> class_id<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="条件函数" tabindex="-1"><a class="header-anchor" href="#条件函数"><span>条件函数</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- IF — 简单条件</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">IF</span><span class="token punctuation">(</span>score <span class="token operator">&gt;=</span> <span class="token number">60</span><span class="token punctuation">,</span> <span class="token string">&#39;及格&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;不及格&#39;</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> result <span class="token keyword">FROM</span> students<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- IFNULL — 空值替换</span></span>
<span class="line"><span class="token keyword">SELECT</span> IFNULL<span class="token punctuation">(</span>email<span class="token punctuation">,</span> <span class="token string">&#39;无邮箱&#39;</span><span class="token punctuation">)</span> <span class="token keyword">FROM</span> users<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- NULLIF — 值相等则返回 NULL</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">NULLIF</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- a = b 时返回 NULL</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- CASE — 多分支条件</span></span>
<span class="line"><span class="token keyword">SELECT</span> name<span class="token punctuation">,</span> score<span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">CASE</span></span>
<span class="line">        <span class="token keyword">WHEN</span> score <span class="token operator">&gt;=</span> <span class="token number">90</span> <span class="token keyword">THEN</span> <span class="token string">&#39;优秀&#39;</span></span>
<span class="line">        <span class="token keyword">WHEN</span> score <span class="token operator">&gt;=</span> <span class="token number">80</span> <span class="token keyword">THEN</span> <span class="token string">&#39;良好&#39;</span></span>
<span class="line">        <span class="token keyword">WHEN</span> score <span class="token operator">&gt;=</span> <span class="token number">60</span> <span class="token keyword">THEN</span> <span class="token string">&#39;及格&#39;</span></span>
<span class="line">        <span class="token keyword">ELSE</span> <span class="token string">&#39;不及格&#39;</span></span>
<span class="line">    <span class="token keyword">END</span> <span class="token keyword">AS</span> grade</span>
<span class="line"><span class="token keyword">FROM</span> students<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="json-函数-mysql-5-7" tabindex="-1"><a class="header-anchor" href="#json-函数-mysql-5-7"><span>JSON 函数（MySQL 5.7+）</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- JSON_OBJECT — 创建 JSON</span></span>
<span class="line"><span class="token keyword">SELECT</span> JSON_OBJECT<span class="token punctuation">(</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;age&#39;</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">-- {&quot;age&quot;: 25, &quot;name&quot;: &quot;张三&quot;}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON_ARRAY — 创建 JSON 数组</span></span>
<span class="line"><span class="token keyword">SELECT</span> JSON_ARRAY<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- [1, 2, 3]</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON_EXTRACT — 提取值（也可以用 -&gt; 和 -&gt;&gt;）</span></span>
<span class="line"><span class="token keyword">SELECT</span> JSON_EXTRACT<span class="token punctuation">(</span><span class="token string">&#39;{&quot;name&quot;: &quot;张三&quot;}&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;$.name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- &quot;张三&quot;</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token string">&#39;{&quot;name&quot;: &quot;张三&quot;}&#39;</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token string">&#39;$.name&#39;</span><span class="token punctuation">;</span>              <span class="token comment">-- &quot;张三&quot;</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token string">&#39;{&quot;name&quot;: &quot;张三&quot;}&#39;</span> <span class="token operator">-</span><span class="token operator">&gt;&gt;</span> <span class="token string">&#39;$.name&#39;</span><span class="token punctuation">;</span>             <span class="token comment">-- 张三（去引号）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON_CONTAINS — 判断是否包含</span></span>
<span class="line"><span class="token keyword">SELECT</span> JSON_CONTAINS<span class="token punctuation">(</span><span class="token string">&#39;[1,2,3]&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;2&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 1</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON_ARRAY_APPEND — 追加元素</span></span>
<span class="line"><span class="token keyword">SELECT</span> JSON_ARRAY_APPEND<span class="token punctuation">(</span><span class="token string">&#39;[1,2]&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;$&#39;</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- [1, 2, 3]</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- JSON_KEYS — 获取所有键</span></span>
<span class="line"><span class="token keyword">SELECT</span> JSON_KEYS<span class="token punctuation">(</span><span class="token string">&#39;{&quot;name&quot;: &quot;张三&quot;, &quot;age&quot;: 25}&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- [&quot;age&quot;, &quot;name&quot;]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="加密函数" tabindex="-1"><a class="header-anchor" href="#加密函数"><span>加密函数</span></a></h2><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- MD5</span></span>
<span class="line"><span class="token keyword">SELECT</span> MD5<span class="token punctuation">(</span><span class="token string">&#39;123456&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- e10adc3949ba59abbe56e057f20f883e</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- SHA1 / SHA2</span></span>
<span class="line"><span class="token keyword">SELECT</span> SHA1<span class="token punctuation">(</span><span class="token string">&#39;123456&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> SHA2<span class="token punctuation">(</span><span class="token string">&#39;123456&#39;</span><span class="token punctuation">,</span> <span class="token number">256</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- SHA-256</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- AES 加密/解密</span></span>
<span class="line"><span class="token keyword">SELECT</span> AES_ENCRYPT<span class="token punctuation">(</span><span class="token string">&#39;hello&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;key&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> AES_DECRYPT<span class="token punctuation">(</span>AES_ENCRYPT<span class="token punctuation">(</span><span class="token string">&#39;hello&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;key&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&#39;key&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 密码哈希</span></span>
<span class="line"><span class="token keyword">SELECT</span> PASSWORD<span class="token punctuation">(</span><span class="token string">&#39;123456&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- MySQL 8.0+ 已废弃，使用认证插件</span></span>
<span class="line"></span></code></pre></div><h2 id="信息函数" tabindex="-1"><a class="header-anchor" href="#信息函数"><span>信息函数</span></a></h2><div class="language-sql" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 数据库/用户信息</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">DATABASE</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">-- 当前数据库</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token keyword">USER</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>         <span class="token comment">-- 当前用户</span></span>
<span class="line"><span class="token keyword">SELECT</span> VERSION<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>      <span class="token comment">-- MySQL 版本</span></span>
<span class="line"><span class="token keyword">SELECT</span> CONNECTION_ID<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">-- 当前连接 ID</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 最后插入的 ID</span></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> students<span class="token punctuation">(</span>name<span class="token punctuation">)</span> <span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token string">&#39;张三&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> LAST_INSERT_ID<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 返回最后插入记录的自增 ID</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 影响行数</span></span>
<span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> students<span class="token punctuation">(</span>name<span class="token punctuation">)</span> <span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token string">&#39;李四&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">SELECT</span> ROW_COUNT<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">-- 1</span></span>
<span class="line"></span></code></pre></div><h2 id="练习" tabindex="-1"><a class="header-anchor" href="#练习"><span>练习</span></a></h2><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code class="language-sql"><span class="line"><span class="token comment">-- 1. 计算每个年龄段的用户数量</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    <span class="token keyword">CASE</span></span>
<span class="line">        <span class="token keyword">WHEN</span> age <span class="token operator">&lt;</span> <span class="token number">18</span> <span class="token keyword">THEN</span> <span class="token string">&#39;未成年&#39;</span></span>
<span class="line">        <span class="token keyword">WHEN</span> age <span class="token operator">BETWEEN</span> <span class="token number">18</span> <span class="token operator">AND</span> <span class="token number">30</span> <span class="token keyword">THEN</span> <span class="token string">&#39;青年&#39;</span></span>
<span class="line">        <span class="token keyword">WHEN</span> age <span class="token operator">BETWEEN</span> <span class="token number">31</span> <span class="token operator">AND</span> <span class="token number">60</span> <span class="token keyword">THEN</span> <span class="token string">&#39;中年&#39;</span></span>
<span class="line">        <span class="token keyword">ELSE</span> <span class="token string">&#39;老年&#39;</span></span>
<span class="line">    <span class="token keyword">END</span> <span class="token keyword">AS</span> age_group<span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> count</span>
<span class="line"><span class="token keyword">FROM</span> users</span>
<span class="line"><span class="token keyword">GROUP</span> <span class="token keyword">BY</span> age_group<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 2. 格式化日期为中文</span></span>
<span class="line"><span class="token keyword">SELECT</span> DATE_FORMAT<span class="token punctuation">(</span>create_at<span class="token punctuation">,</span> <span class="token string">&#39;%Y年%m月%d日 %H:%i&#39;</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> create_time <span class="token keyword">FROM</span> orders<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">-- 3. 计算订单金额区间分布</span></span>
<span class="line"><span class="token keyword">SELECT</span></span>
<span class="line">    <span class="token keyword">CASE</span></span>
<span class="line">        <span class="token keyword">WHEN</span> amount <span class="token operator">&lt;</span> <span class="token number">100</span> <span class="token keyword">THEN</span> <span class="token string">&#39;小额&#39;</span></span>
<span class="line">        <span class="token keyword">WHEN</span> amount <span class="token operator">BETWEEN</span> <span class="token number">100</span> <span class="token operator">AND</span> <span class="token number">1000</span> <span class="token keyword">THEN</span> <span class="token string">&#39;中额&#39;</span></span>
<span class="line">        <span class="token keyword">ELSE</span> <span class="token string">&#39;大额&#39;</span></span>
<span class="line">    <span class="token keyword">END</span> <span class="token keyword">AS</span> amount_level<span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> order_count<span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">SUM</span><span class="token punctuation">(</span>amount<span class="token punctuation">)</span> <span class="token keyword">AS</span> total_amount</span>
<span class="line"><span class="token keyword">FROM</span> orders</span>
<span class="line"><span class="token keyword">GROUP</span> <span class="token keyword">BY</span> amount_level<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,20)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};